// JoltPhysics/Jolt/Math/Quat.h:32:1
/// Quaternion class, quaternions are 4 dimensional vectors which can describe rotations in 3 dimensional
/// space if their length is 1.
///
/// They are written as:
///
/// \f$q = w + x \: i + y \: j + z \: k\f$
///
/// or in vector notation:
///
/// \f$q = [w, v] = [w, x, y, z]\f$
///
/// Where:
///
/// w = the real part
/// v = the imaginary part, (x, y, z)
///
/// Note that we store the quaternion in a Vec4 as [x, y, z, w] because that makes
/// it easy to extract the rotation axis of the quaternion:
///
/// q = [cos(angle / 2), sin(angle / 2) * rotation_axis]
typedef struct JPH_Quat {
    /// 4 vector that stores [x, y, z, w] parts of the quaternion
    JPH_Vec4 mValue;
} JPH_Quat;

///@name Constructors
///@{
void JPH_Quat_Construct(JPH_Quat *self);
void JPH_Quat_ConstructWithRHS(JPH_Quat *self, const JPH_Quat *inRHS);
void JPH_Quat_ConstructWithXYZW(JPH_Quat *self, float inX, float inY, float inZ, float inW);
void JPH_Quat_ConstructWithFloat4(JPH_Quat *self, const JPH_Float4 *inV);
void JPH_Quat_ConstructWithVec4(JPH_Quat *self, const JPH_Vec4 inV);
/// If this quaternion is close to inRHS. Note that q and -q represent the same rotation, this is not checked here.
bool JPH_Quat_IsClose(const JPH_Quat *self, const JPH_Quat inRHS, float inMaxDistSq);
/// If the length of this quaternion is 1 +/- inTolerance
bool JPH_Quat_IsNormalized(const JPH_Quat *self, float inTolerance);
/// If any component of this quaternion is a NaN (not a number)
bool JPH_Quat_IsNaN(const JPH_Quat *self);
/// Get X component (imaginary part i)
float JPH_Quat_GetX(const JPH_Quat *self);
/// Get Y component (imaginary part j)
float JPH_Quat_GetY(const JPH_Quat *self);
/// Get Z component (imaginary part k)
float JPH_Quat_GetZ(const JPH_Quat *self);
/// Get W component (real part)
float JPH_Quat_GetW(const JPH_Quat *self);
/// Get the imaginary part of the quaternion
JPH_Vec3 JPH_Quat_GetXYZ(const JPH_Quat *self);
/// Get the quaternion as a Vec4
JPH_Vec4 JPH_Quat_GetXYZW(const JPH_Quat *self);
/// Set individual components
void JPH_Quat_SetX(JPH_Quat *self, float inX);
void JPH_Quat_SetY(JPH_Quat *self, float inY);
void JPH_Quat_SetZ(JPH_Quat *self, float inZ);
void JPH_Quat_SetW(JPH_Quat *self, float inW);
/// Set all components
void JPH_Quat_Set(JPH_Quat *self, float inX, float inY, float inZ, float inW);
/// @return [0, 0, 0, 0]
JPH_Quat JPH_Quat_sZero();
/// @return [1, 0, 0, 0] (or in storage format Quat(0, 0, 0, 1))
JPH_Quat JPH_Quat_sIdentity();
/// Rotation from axis and angle
JPH_Quat JPH_Quat_sRotation(const JPH_Vec3 inAxis, float inAngle);
/// Get axis and angle that represents this quaternion, outAngle will always be in the range \f$[0, \pi]\f$
void JPH_Quat_GetAxisAngle(const JPH_Quat *self, JPH_Vec3 *outAxis, float *outAngle);
/// Create quaternion that rotates a vector from the direction of inFrom to the direction of inTo along the shortest path
/// @see https://www.euclideanspace.com/maths/algebra/vectors/angleBetween/index.htm
JPH_Quat JPH_Quat_sFromTo(const JPH_Vec3 inFrom, const JPH_Vec3 inTo);
