// JoltPhysics/Jolt/Physics/Body/MotionProperties.h:28:1
/// The Body class only keeps track of state for static bodies, the MotionProperties class keeps the additional state needed for a moving Body. It has a 1-on-1 relationship with the body.
typedef struct JPH_MotionProperties {
    ///< World space linear velocity of the center of mass (m/s)
    JPH_Vec3 mLinearVelocity;
    ///< World space angular velocity (rad/s)
    JPH_Vec3 mAngularVelocity;
    ///< Diagonal of inverse inertia matrix: D
    JPH_Vec3 mInvInertiaDiagonal;
    ///< Rotation (R) that takes inverse inertia diagonal to local space: Ibody^-1 = R * D * R^-1
    JPH_Quat mInertiaRotation;
    ///< Accumulated world space force (N). Note loaded through intrinsics so ensure that the 4 bytes after this are readable!
    JPH_Float3 mForce;
    ///< Accumulated world space torque (N m). Note loaded through intrinsics so ensure that the 4 bytes after this are readable!
    JPH_Float3 mTorque;
    ///< Inverse mass of the object (1/kg)
    float mInvMass;
    ///< Linear damping: dv/dt = -c * v. c must be between 0 and 1 but is usually close to 0.
    float mLinearDamping;
    ///< Angular damping: dw/dt = -c * w. c must be between 0 and 1 but is usually close to 0.
    float mAngularDamping;
    ///< Maximum linear velocity that this body can reach (m/s)
    float mMaxLinearVelocity;
    ///< Maximum angular velocity that this body can reach (rad/s)
    float mMaxAngularVelocity;
    ///< Factor to multiply gravity with
    float mGravityFactor;
    ///< If the body is active, this is the index in the active body list or cInactiveIndex if it is not active (note that there are 2 lists, one for rigid and one for soft bodies)
    uint32_t mIndexInActiveBodies;
    ///< Index of the island that this body is part of, when the body has not yet been updated or is not active this is cInactiveIndex
    uint32_t mIslandIndex;
    ///< Motion quality, or how well it detects collisions when it has a high velocity
    JPH_EMotionQuality mMotionQuality;
    ///< If this body can go to sleep
    bool mAllowSleeping;
    ///< Allowed degrees of freedom for this body
    JPH_EAllowedDOFs mAllowedDOFs;
    ///< Used only when this body is dynamic and colliding. Override for the number of solver velocity iterations to run, 0 means use the default in PhysicsSettings::mNumVelocitySteps. The number of iterations to use is the max of all contacts and constraints in the island.
    uint8_t mNumVelocityStepsOverride;
    ///< Used only when this body is dynamic and colliding. Override for the number of solver position iterations to run, 0 means use the default in PhysicsSettings::mNumPositionSteps. The number of iterations to use is the max of all contacts and constraints in the island.
    uint8_t mNumPositionStepsOverride;
    ///< Measure motion for 3 points on the body to see if it is resting: COM, COM + largest bounding box axis, COM + second largest bounding box axis
    JPH_Sphere mSleepTestSpheres[3];
    ///< How long this body has been within the movement tolerance
    float mSleepTestTimer;
    ///< Copied from Body::mBodyType and cached for asserting purposes
    JPH_EBodyType mCachedBodyType;
    ///< Copied from Body::mMotionType and cached for asserting purposes
    JPH_EMotionType mCachedMotionType;
} JPH_MotionProperties;

/// Motion quality, or how well it detects collisions when it has a high velocity
JPH_EMotionQuality JPH_MotionProperties_GetMotionQuality(const JPH_MotionProperties *self);
/// Get the allowed degrees of freedom that this body has (this can be changed by calling SetMassProperties)
JPH_EAllowedDOFs JPH_MotionProperties_GetAllowedDOFs(const JPH_MotionProperties *self);
/// If this body can go to sleep.
bool JPH_MotionProperties_GetAllowSleeping(const JPH_MotionProperties *self);
/// Get world space linear velocity of the center of mass
JPH_Vec3 JPH_MotionProperties_GetLinearVelocity(const JPH_MotionProperties *self);
/// Set world space linear velocity of the center of mass
void JPH_MotionProperties_SetLinearVelocity(JPH_MotionProperties *self, const JPH_Vec3 inLinearVelocity);
/// Set world space linear velocity of the center of mass, will make sure the value is clamped against the maximum linear velocity
void JPH_MotionProperties_SetLinearVelocityClamped(JPH_MotionProperties *self, const JPH_Vec3 inLinearVelocity);
/// Get world space angular velocity of the center of mass
JPH_Vec3 JPH_MotionProperties_GetAngularVelocity(const JPH_MotionProperties *self);
/// Set world space angular velocity of the center of mass
void JPH_MotionProperties_SetAngularVelocity(JPH_MotionProperties *self, const JPH_Vec3 inAngularVelocity);
/// Set world space angular velocity of the center of mass, will make sure the value is clamped against the maximum angular velocity
void JPH_MotionProperties_SetAngularVelocityClamped(JPH_MotionProperties *self, const JPH_Vec3 inAngularVelocity);
/// Set velocity of body such that it will be rotate/translate by inDeltaPosition/Rotation in inDeltaTime seconds.
void JPH_MotionProperties_MoveKinematic(JPH_MotionProperties *self, const JPH_Vec3 inDeltaPosition, const JPH_Quat inDeltaRotation, float inDeltaTime);
/// Maximum linear velocity that a body can achieve. Used to prevent the system from exploding.
float JPH_MotionProperties_GetMaxLinearVelocity(const JPH_MotionProperties *self);
void JPH_MotionProperties_SetMaxLinearVelocity(JPH_MotionProperties *self, float inLinearVelocity);
/// Maximum angular velocity that a body can achieve. Used to prevent the system from exploding.
float JPH_MotionProperties_GetMaxAngularVelocity(const JPH_MotionProperties *self);
void JPH_MotionProperties_SetMaxAngularVelocity(JPH_MotionProperties *self, float inAngularVelocity);
/// Clamp velocity according to limit
void JPH_MotionProperties_ClampLinearVelocity(JPH_MotionProperties *self);
void JPH_MotionProperties_ClampAngularVelocity(JPH_MotionProperties *self);
/// Get linear damping: dv/dt = -c * v. c must be between 0 and 1 but is usually close to 0.
float JPH_MotionProperties_GetLinearDamping(const JPH_MotionProperties *self);
void JPH_MotionProperties_SetLinearDamping(JPH_MotionProperties *self, float inLinearDamping);
/// Get angular damping: dw/dt = -c * w. c must be between 0 and 1 but is usually close to 0.
float JPH_MotionProperties_GetAngularDamping(const JPH_MotionProperties *self);
void JPH_MotionProperties_SetAngularDamping(JPH_MotionProperties *self, float inAngularDamping);
/// Get gravity factor (1 = normal gravity, 0 = no gravity)
float JPH_MotionProperties_GetGravityFactor(const JPH_MotionProperties *self);
void JPH_MotionProperties_SetGravityFactor(JPH_MotionProperties *self, float inGravityFactor);
/// Set the mass and inertia tensor
void JPH_MotionProperties_SetMassProperties(JPH_MotionProperties *self, JPH_EAllowedDOFs inAllowedDOFs, const JPH_MassProperties *inMassProperties);
/// Get inverse mass (1 / mass). Should only be called on a dynamic object (static or kinematic bodies have infinite mass so should be treated as 1 / mass = 0)
float JPH_MotionProperties_GetInverseMass(const JPH_MotionProperties *self);
float JPH_MotionProperties_GetInverseMassUnchecked(const JPH_MotionProperties *self);
/// Set the inverse mass (1 / mass).
/// Note that mass and inertia are linearly related (e.g. inertia of a sphere with mass m and radius r is \f$2/5 \: m \: r^2\f$).
/// If you change mass, inertia should probably change as well. You can use ScaleToMass to update mass and inertia at the same time.
/// If all your translation degrees of freedom are restricted, make sure this is zero (see EAllowedDOFs).
void JPH_MotionProperties_SetInverseMass(JPH_MotionProperties *self, float inInverseMass);
/// Diagonal of inverse inertia matrix: D. Should only be called on a dynamic object (static or kinematic bodies have infinite mass so should be treated as D = 0)
JPH_Vec3 JPH_MotionProperties_GetInverseInertiaDiagonal(const JPH_MotionProperties *self);
/// Rotation (R) that takes inverse inertia diagonal to local space: \f$I_{body}^{-1} = R \: D \: R^{-1}\f$
JPH_Quat JPH_MotionProperties_GetInertiaRotation(const JPH_MotionProperties *self);
/// Set the inverse inertia tensor in local space by setting the diagonal and the rotation: \f$I_{body}^{-1} = R \: D \: R^{-1}\f$.
/// Note that mass and inertia are linearly related (e.g. inertia of a sphere with mass m and radius r is \f$2/5 \: m \: r^2\f$).
/// If you change inertia, mass should probably change as well. You can use ScaleToMass to update mass and inertia at the same time.
/// If all your rotation degrees of freedom are restricted, make sure this is zero (see EAllowedDOFs).
void JPH_MotionProperties_SetInverseInertia(JPH_MotionProperties *self, const JPH_Vec3 inDiagonal, const JPH_Quat inRot);
/// Sets the mass to inMass and scale the inertia tensor based on the ratio between the old and new mass.
/// Note that this only works when the current mass is finite (i.e. the body is dynamic and translational degrees of freedom are not restricted).
void JPH_MotionProperties_ScaleToMass(JPH_MotionProperties *self, float inMass);
/// Get inverse inertia matrix (\f$I_{body}^{-1}\f$). Will be a matrix of zeros for a static or kinematic object.
JPH_Mat44 JPH_MotionProperties_GetLocalSpaceInverseInertia(const JPH_MotionProperties *self);
/// Same as GetLocalSpaceInverseInertia() but doesn't check if the body is dynamic
JPH_Mat44 JPH_MotionProperties_GetLocalSpaceInverseInertiaUnchecked(const JPH_MotionProperties *self);
/// Get inverse inertia matrix (\f$I^{-1}\f$) for a given object rotation (translation will be ignored). Zero if object is static or kinematic.
JPH_Mat44 JPH_MotionProperties_GetInverseInertiaForRotation(const JPH_MotionProperties *self, const JPH_Mat44 * inRotation);
/// Multiply a vector with the inverse world space inertia tensor (\f$I_{world}^{-1}\f$). Zero if object is static or kinematic.
JPH_Vec3 JPH_MotionProperties_MultiplyWorldSpaceInverseInertiaByVector(const JPH_MotionProperties *self, const JPH_Quat inBodyRotation, const JPH_Vec3 inV);
/// Velocity of point inPoint (in center of mass space, e.g. on the surface of the body) of the body (unit: m/s)
JPH_Vec3 JPH_MotionProperties_GetPointVelocityCOM(const JPH_MotionProperties *self, const JPH_Vec3 inPointRelativeToCOM);
// Get the total amount of force applied to the center of mass this time step (through Body::AddForce calls). Note that it will reset to zero after PhysicsSystem::Update.
JPH_Vec3 JPH_MotionProperties_GetAccumulatedForce(const JPH_MotionProperties *self);
// Get the total amount of torque applied to the center of mass this time step (through Body::AddForce/Body::AddTorque calls). Note that it will reset to zero after PhysicsSystem::Update.
JPH_Vec3 JPH_MotionProperties_GetAccumulatedTorque(const JPH_MotionProperties *self);
// Reset the total accumulated force, note that this will be done automatically after every time step.
void JPH_MotionProperties_ResetForce(JPH_MotionProperties *self);
// Reset the total accumulated torque, note that this will be done automatically after every time step.
void JPH_MotionProperties_ResetTorque(JPH_MotionProperties *self);
// Reset the current velocity and accumulated force and torque.
void JPH_MotionProperties_ResetMotion(JPH_MotionProperties *self);
/// Returns a vector where the linear components that are not allowed by mAllowedDOFs are set to 0 and the rest to 0xffffffff
JPH_UVec4 JPH_MotionProperties_GetLinearDOFsMask(const JPH_MotionProperties *self);
/// Takes a translation vector inV and returns a vector where the components that are not allowed by mAllowedDOFs are set to 0
JPH_Vec3 JPH_MotionProperties_LockTranslation(const JPH_MotionProperties *self, const JPH_Vec3 inV);
/// Returns a vector where the angular components that are not allowed by mAllowedDOFs are set to 0 and the rest to 0xffffffff
JPH_UVec4 JPH_MotionProperties_GetAngularDOFsMask(const JPH_MotionProperties *self);
/// Takes an angular velocity / torque vector inV and returns a vector where the components that are not allowed by mAllowedDOFs are set to 0
JPH_Vec3 JPH_MotionProperties_LockAngular(const JPH_MotionProperties *self, const JPH_Vec3 inV);
/// Used only when this body is dynamic and colliding. Override for the number of solver velocity iterations to run, 0 means use the default in PhysicsSettings::mNumVelocitySteps. The number of iterations to use is the max of all contacts and constraints in the island.
void JPH_MotionProperties_SetNumVelocityStepsOverride(JPH_MotionProperties *self, uint32_t inN);
uint32_t JPH_MotionProperties_GetNumVelocityStepsOverride(const JPH_MotionProperties *self);
/// Used only when this body is dynamic and colliding. Override for the number of solver position iterations to run, 0 means use the default in PhysicsSettings::mNumPositionSteps. The number of iterations to use is the max of all contacts and constraints in the island.
void JPH_MotionProperties_SetNumPositionStepsOverride(JPH_MotionProperties *self, uint32_t inN);
uint32_t JPH_MotionProperties_GetNumPositionStepsOverride(const JPH_MotionProperties *self);
///@name Update linear and angular velocity (used during constraint solving)
///@{
void JPH_MotionProperties_AddLinearVelocityStep(JPH_MotionProperties *self, const JPH_Vec3 inLinearVelocityChange);
void JPH_MotionProperties_SubLinearVelocityStep(JPH_MotionProperties *self, const JPH_Vec3 inLinearVelocityChange);
void JPH_MotionProperties_AddAngularVelocityStep(JPH_MotionProperties *self, const JPH_Vec3 inAngularVelocityChange);
void JPH_MotionProperties_SubAngularVelocityStep(JPH_MotionProperties *self, const JPH_Vec3 inAngularVelocityChange);
/// Apply the gyroscopic force (aka Dzhanibekov effect, see https://en.wikipedia.org/wiki/Tennis_racket_theorem)
void JPH_MotionProperties_ApplyGyroscopicForceInternal(JPH_MotionProperties *self, const JPH_Quat inBodyRotation, float inDeltaTime);
/// Apply all accumulated forces, torques and drag (should only be called by the PhysicsSystem)
void JPH_MotionProperties_ApplyForceTorqueAndDragInternal(JPH_MotionProperties *self, const JPH_Quat inBodyRotation, const JPH_Vec3 inGravity, float inDeltaTime);
/// Access to the island index
uint32_t JPH_MotionProperties_GetIslandIndexInternal(const JPH_MotionProperties *self);
void JPH_MotionProperties_SetIslandIndexInternal(JPH_MotionProperties *self, uint32_t inIndex);
/// Access to the index in the active bodies array
uint32_t JPH_MotionProperties_GetIndexInActiveBodiesInternal(const JPH_MotionProperties *self);
/// Reset spheres to center around inPoints with radius 0
void JPH_MotionProperties_ResetSleepTestSpheres(JPH_MotionProperties *self, const JPH_RVec3 *inPoints);
/// Reset the sleep test timer without resetting the sleep test spheres
void JPH_MotionProperties_ResetSleepTestTimer(JPH_MotionProperties *self);
